import React, { useEffect, useState } from 'react';
import { adminAPI } from '../services/api';
import { Line, Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS, CategoryScale, LinearScale, PointElement,
  LineElement, BarElement, Title, Tooltip, Legend, Filler
} from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, BarElement, Title, Tooltip, Legend, Filler);

function StatCard({ label, value, icon, change, color = 'primary' }) {
  return (
    <div className="stat-card">
      <div className="flex items-center justify-between mb-3">
        <span className="text-2xl">{icon}</span>
        {change != null && (
          <span className={`text-xs font-medium ${change >= 0 ? 'text-green-400' : 'text-red-400'}`}>
            {change >= 0 ? '↑' : '↓'} {Math.abs(change)}%
          </span>
        )}
      </div>
      <p className="font-display font-bold text-3xl text-white">{value}</p>
      <p className="text-gray-500 text-sm mt-1">{label}</p>
    </div>
  );
}

export default function Dashboard() {
  const [stats, setStats] = useState({ users: 0, venues: 0, reservations: 0, revenue: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [users, venues, reservations, payments] = await Promise.all([
          adminAPI.users({ page_size: 1 }),
          adminAPI.venues({ page_size: 1 }),
          adminAPI.reservations({ page_size: 1 }),
          adminAPI.payments({ page_size: 1 }),
        ]);
        setStats({
          users: users.data.count || 0,
          venues: venues.data.count || 0,
          reservations: reservations.data.count || 0,
          revenue: 0,
        });
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  const revenueData = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
    datasets: [{
      label: 'Revenue ($)',
      data: [1200, 1900, 3000, 2500, 4200, 3800, 5100],
      fill: true,
      borderColor: '#FF3D57',
      backgroundColor: 'rgba(255,61,87,0.1)',
      tension: 0.4,
    }],
  };

  const reservationData = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [{
      label: 'Reservations',
      data: [42, 38, 55, 61, 82, 110, 95],
      backgroundColor: 'rgba(123,47,190,0.5)',
      borderColor: '#7B2FBE',
      borderRadius: 8,
    }],
  };

  const chartOptions = {
    responsive: true,
    plugins: { legend: { display: false } },
    scales: {
      x: { grid: { color: '#1E1E2E' }, ticks: { color: '#6B7280' } },
      y: { grid: { color: '#1E1E2E' }, ticks: { color: '#6B7280' } },
    },
  };

  return (
    <div className="space-y-6">
      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Total Users" value={stats.users.toLocaleString()} icon="👥" change={12} />
        <StatCard label="Active Venues" value={stats.venues.toLocaleString()} icon="🏢" change={8} />
        <StatCard label="Reservations" value={stats.reservations.toLocaleString()} icon="📋" change={23} />
        <StatCard label="Revenue" value={`$${stats.revenue.toLocaleString()}`} icon="💰" change={18} />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-card border border-border rounded-2xl p-5">
          <h2 className="font-semibold text-white mb-4">Revenue Overview</h2>
          <Line data={revenueData} options={chartOptions} />
        </div>
        <div className="bg-card border border-border rounded-2xl p-5">
          <h2 className="font-semibold text-white mb-4">Weekly Reservations</h2>
          <Bar data={reservationData} options={chartOptions} />
        </div>
      </div>

      {/* Quick actions */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        {[
          { icon: '🏢', label: 'Pending Venue Approvals', to: '/venues', color: 'yellow' },
          { icon: '🎥', label: 'Stories to Moderate', to: '/stories', color: 'purple' },
          { icon: '⚠️', label: 'Support Disputes', to: '/reservations', color: 'red' },
        ].map((item) => (
          <a key={item.label} href={item.to} className="bg-card border border-border rounded-2xl p-4 flex items-center space-x-3 hover:border-primary/40 transition-colors">
            <span className="text-2xl">{item.icon}</span>
            <span className="text-sm text-gray-300">{item.label}</span>
          </a>
        ))}
      </div>
    </div>
  );
}
